import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Bookmark {
  id: string;
  title: string;
  url?: string;
  parentId?: string;
  dateAdded?: number;
  folderPath?: string[];
}

export enum ViewMode {
  LIST = 'LIST',
  GRID = 'GRID'
}

import { Bookmark } from '../types';

/**
 * Recursively flattens the bookmark tree provided by Chrome.
 */
const flattenBookmarks = (nodes: any[], path: string[] = []): Bookmark[] => {
  let results: Bookmark[] = [];
  for (const node of nodes) {
    if (node.url) {
      results.push({
        id: node.id,
        title: node.title || node.url,
        url: node.url,
        parentId: node.parentId,
        dateAdded: node.dateAdded,
        folderPath: path
      });
    }
    if (node.children) {
      results = results.concat(flattenBookmarks(node.children, [...path, node.title]));
    }
  }
  return results;
};

/**
 * Mock data for when running outside of a Chrome Extension environment.
 */
const MOCK_BOOKMARKS: Bookmark[] = [
  { id: '1', title: 'GitHub', url: 'https://github.com', folderPath: ['Work', 'Dev'] },
  { id: '2', title: 'Stack Overflow', url: 'https://stackoverflow.com', folderPath: ['Work', 'Dev'] },
  { id: '3', title: 'Gmail', url: 'https://mail.google.com', folderPath: ['Personal'] },
  { id: '4', title: 'YouTube', url: 'https://youtube.com', folderPath: ['Entertainment'] },
  { id: '5', title: 'Gemini AI', url: 'https://gemini.google.com', folderPath: ['AI'] },
  { id: '6', title: 'Tailwind CSS', url: 'https://tailwindcss.com', folderPath: ['Docs'] },
  { id: '7', title: 'React Documentation', url: 'https://react.dev', folderPath: ['Docs', 'Frontend'] },
  { id: '8', title: 'Netflix', url: 'https://netflix.com', folderPath: ['Entertainment'] },
];

export const getBookmarks = async (): Promise<Bookmark[]> => {
  // Check if we are in a Chrome extension environment
  if (typeof chrome !== 'undefined' && chrome.bookmarks) {
    return new Promise((resolve) => {
      chrome.bookmarks.getTree((tree) => {
        resolve(flattenBookmarks(tree));
      });
    });
  }

  // Return mock data for development preview
  return new Promise((resolve) => {
    setTimeout(() => resolve(MOCK_BOOKMARKS), 300);
  });
};

export const openBookmark = (url: string, newTab: boolean = true) => {
  if (typeof chrome !== 'undefined' && chrome.tabs) {
    if (newTab) {
      chrome.tabs.create({ url });
    } else {
      chrome.tabs.update({ url });
    }
    window.close(); // Close the popup/extension UI
  } else {
    // Development preview behavior
    window.open(url, '_blank');
  }
};

import React from 'react';
import { Bookmark } from '../types';

interface BookmarkItemProps {
  bookmark: Bookmark;
  isSelected: boolean;
  onSelect: (url: string) => void;
  onMouseEnter: () => void;
}

const BookmarkItem: React.FC<BookmarkItemProps> = ({ bookmark, isSelected, onSelect, onMouseEnter }) => {
  // Get favicon from URL if possible
  const faviconUrl = bookmark.url 
    ? `https://www.google.com/s2/favicons?domain=${new URL(bookmark.url).hostname}&sz=32`
    : 'https://picsum.photos/32/32';

  return (
    <div
      onMouseEnter={onMouseEnter}
      onClick={() => bookmark.url && onSelect(bookmark.url)}
      className={`group flex items-center gap-4 px-4 py-3 cursor-pointer transition-all duration-150 border-l-4 ${
        isSelected 
          ? 'bg-blue-50 border-blue-500' 
          : 'bg-white border-transparent hover:bg-gray-50'
      }`}
    >
      <div className="flex-shrink-0 w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center overflow-hidden">
        <img 
          src={faviconUrl} 
          alt="" 
          className="w-5 h-5 object-contain"
          onError={(e) => (e.currentTarget.src = 'https://picsum.photos/32/32')}
        />
      </div>

      <div className="flex-grow min-w-0">
        <div className="flex items-center gap-2">
          <span className={`text-sm font-semibold truncate ${isSelected ? 'text-blue-700' : 'text-gray-900'}`}>
            {bookmark.title}
          </span>
          {bookmark.folderPath && bookmark.folderPath.length > 0 && (
            <div className="flex items-center gap-1">
              {bookmark.folderPath.filter(p => p && p !== 'Bookmarks Bar' && p !== 'Other Bookmarks').map((folder, idx) => (
                <span key={idx} className="text-[10px] px-1.5 py-0.5 bg-gray-100 text-gray-500 rounded uppercase tracking-wider font-bold">
                  {folder}
                </span>
              ))}
            </div>
          )}
        </div>
        <div className="text-xs text-gray-400 truncate mt-0.5">
          {bookmark.url}
        </div>
      </div>

      {isSelected && (
        <div className="flex-shrink-0 flex items-center gap-1 text-[10px] font-bold text-blue-400 bg-blue-50 px-2 py-1 rounded border border-blue-100 animate-pulse">
          <span>PRESS ENTER</span>
          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
          </svg>
        </div>
      )}
    </div>
  );
};

export default BookmarkItem;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Bookmark } from './types';
import { getBookmarks, openBookmark } from './services/bookmarkService';
import BookmarkItem from './components/BookmarkItem';

const App: React.FC = () => {
  const [bookmarks, setBookmarks] = useState<Bookmark[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [isLoading, setIsLoading] = useState(true);

  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Initialize data
  useEffect(() => {
    const loadData = async () => {
      try {
        const data = await getBookmarks();
        setBookmarks(data);
      } catch (error) {
        console.error('Failed to load bookmarks', error);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();

    // Focus input on mount
    inputRef.current?.focus();
  }, []);

  // Filter bookmarks based on search query
  const filteredBookmarks = useMemo(() => {
    if (!searchQuery.trim()) return bookmarks.slice(0, 50); // Show recent or first few when empty

    const query = searchQuery.toLowerCase();
    return bookmarks.filter(b => 
      b.title.toLowerCase().includes(query) || 
      (b.url && b.url.toLowerCase().includes(query)) ||
      (b.folderPath && b.folderPath.some(f => f.toLowerCase().includes(query)))
    );
  }, [bookmarks, searchQuery]);

  // Reset selection when query changes
  useEffect(() => {
    setSelectedIndex(0);
  }, [searchQuery]);

  // Handle keyboard navigation
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (filteredBookmarks.length === 0) return;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setSelectedIndex(prev => (prev + 1) % filteredBookmarks.length);
        break;
      case 'ArrowUp':
        e.preventDefault();
        setSelectedIndex(prev => (prev - 1 + filteredBookmarks.length) % filteredBookmarks.length);
        break;
      case 'Enter':
        e.preventDefault();
        const selected = filteredBookmarks[selectedIndex];
        if (selected && selected.url) {
          openBookmark(selected.url);
        }
        break;
      case 'Escape':
        // In extension context, this closes the popup
        window.close();
        break;
    }
  }, [filteredBookmarks, selectedIndex]);

  // Scroll active item into view
  useEffect(() => {
    const activeItem = scrollContainerRef.current?.children[selectedIndex] as HTMLElement;
    if (activeItem) {
      activeItem.scrollIntoView({
        behavior: 'smooth',
        block: 'nearest',
      });
    }
  }, [selectedIndex]);

  return (
    <div className="flex flex-col w-full max-w-2xl mx-auto h-[500px] bg-white shadow-2xl overflow-hidden ring-1 ring-black/5 rounded-xl border border-gray-100">
      {/* Search Header */}
      <div className="relative flex-shrink-0 bg-white border-b border-gray-100 px-4 py-4">
        <div className="relative flex items-center">
          <svg className="absolute left-3 w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          <input
            ref={inputRef}
            type="text"
            className="w-full pl-11 pr-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-blue-500 text-gray-800 placeholder-gray-400 text-lg outline-none transition-all"
            placeholder="Search bookmarks by name, URL, or folder..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onKeyDown={handleKeyDown}
            autoFocus
          />
        </div>
      </div>

      {/* Results Body */}
      <div 
        ref={scrollContainerRef}
        className="flex-grow overflow-y-auto no-scrollbar bg-white"
      >
        {isLoading ? (
          <div className="flex flex-col items-center justify-center h-full space-y-4">
            <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-500 text-sm font-medium">Fetching your bookmarks...</p>
          </div>
        ) : filteredBookmarks.length > 0 ? (
          filteredBookmarks.map((bookmark, index) => (
            <BookmarkItem
              key={bookmark.id}
              bookmark={bookmark}
              isSelected={index === selectedIndex}
              onSelect={openBookmark}
              onMouseEnter={() => setSelectedIndex(index)}
            />
          ))
        ) : (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
              <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <p className="text-gray-600 font-semibold">No bookmarks found</p>
            <p className="text-gray-400 text-sm mt-1">Try a different search term or check your browser bookmarks.</p>
          </div>
        )}
      </div>

      {/* Footer / Status Bar */}
      <div className="flex-shrink-0 bg-gray-50 border-t border-gray-100 px-4 py-2 flex items-center justify-between text-[11px] text-gray-500 font-medium">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1">
            <span className="bg-white border border-gray-300 rounded px-1 py-0.5 text-[9px] shadow-sm">↑↓</span>
            <span>Navigate</span>
          </div>
          <div className="flex items-center gap-1">
            <span className="bg-white border border-gray-300 rounded px-1 py-0.5 text-[9px] shadow-sm">↵</span>
            <span>Open</span>
          </div>
          <div className="flex items-center gap-1">
            <span className="bg-white border border-gray-300 rounded px-1 py-0.5 text-[9px] shadow-sm">ESC</span>
            <span>Close</span>
          </div>
        </div>
        <div>
          {filteredBookmarks.length} {filteredBookmarks.length === 1 ? 'result' : 'results'} found
        </div>
      </div>
    </div>
  );
};

export default App;

