import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Bookmark } from './types';
import { getBookmarks, openBookmark } from './services/bookmarkService';
import BookmarkItem from './components/BookmarkItem';

const App: React.FC = () => {
  const [bookmarks, setBookmarks] = useState<Bookmark[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const data = await getBookmarks();
        setBookmarks(data);
      } catch (err) {
        console.error('Bookmark error:', err);
        setError('No se pudieron cargar los marcadores. Revisa los permisos.');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();

    const timer = setTimeout(() => {
      inputRef.current?.focus();
    }, 300);
    return () => clearTimeout(timer);
  }, []);

  const filteredBookmarks = useMemo(() => {
    if (!searchQuery.trim()) return bookmarks.slice(0, 100);
    const query = searchQuery.toLowerCase();
    return bookmarks.filter(b => 
      b.title.toLowerCase().includes(query) || 
      (b.url && b.url.toLowerCase().includes(query)) ||
      (b.folderPath && b.folderPath.some(f => f.toLowerCase().includes(query)))
    );
  }, [bookmarks, searchQuery]);

  useEffect(() => {
    setSelectedIndex(0);
  }, [searchQuery]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (filteredBookmarks.length === 0) return;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setSelectedIndex(prev => (prev + 1) % filteredBookmarks.length);
        break;
      case 'ArrowUp':
        e.preventDefault();
        setSelectedIndex(prev => (prev - 1 + filteredBookmarks.length) % filteredBookmarks.length);
        break;
      case 'Enter':
        e.preventDefault();
        const selected = filteredBookmarks[selectedIndex];
        if (selected && selected.url) {
          openBookmark(selected.url);
        }
        break;
      case 'Escape':
        window.close();
        break;
    }
  }, [filteredBookmarks, selectedIndex]);

  useEffect(() => {
    const container = scrollContainerRef.current;
    if (!container) return;

    const activeItem = container.children[selectedIndex] as HTMLElement;
    if (activeItem) {
      const containerHeight = container.offsetHeight;
      const itemTop = activeItem.offsetTop;
      const itemHeight = activeItem.offsetHeight;
      const scrollTop = container.scrollTop;

      if (itemTop < scrollTop) {
        container.scrollTop = itemTop;
      } else if (itemTop + itemHeight > scrollTop + containerHeight) {
        container.scrollTop = itemTop + itemHeight - containerHeight;
      }
    }
  }, [selectedIndex]);

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center bg-red-50">
        <div className="text-red-500 font-bold mb-2">Error de Inicialización</div>
        <p className="text-red-600 text-sm">{error}</p>
        <button onClick={() => window.location.reload()} className="mt-4 px-4 py-2 bg-red-600 text-white rounded-lg text-sm">
          Reintentar
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col w-full h-full bg-white overflow-hidden">
      <div className="relative flex-shrink-0 bg-white border-b border-gray-100 px-4 py-4">
        <div className="relative flex items-center">
          <svg className="absolute left-3 w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          <input
            ref={inputRef}
            type="text"
            className="w-full pl-11 pr-4 py-3 bg-gray-50 border-none rounded-xl focus:ring-2 focus:ring-blue-500 text-gray-800 placeholder-gray-400 text-lg outline-none transition-all shadow-inner"
            placeholder="Escribe para buscar..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onKeyDown={handleKeyDown}
          />
        </div>
      </div>

      <div ref={scrollContainerRef} className="flex-grow overflow-y-auto no-scrollbar bg-white relative">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center h-full space-y-4">
            <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-500 text-sm font-medium">Accediendo a marcadores...</p>
          </div>
        ) : filteredBookmarks.length > 0 ? (
          filteredBookmarks.map((bookmark, index) => (
            <BookmarkItem
              key={bookmark.id}
              bookmark={bookmark}
              isSelected={index === selectedIndex}
              onSelect={openBookmark}
              onMouseEnter={() => setSelectedIndex(index)}
            />
          ))
        ) : (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center">
            <p className="text-gray-600 font-semibold">No hay resultados</p>
            <p className="text-gray-400 text-sm mt-1">Intenta con otra palabra clave.</p>
          </div>
        )}
      </div>

      <div className="flex-shrink-0 bg-gray-50 border-t border-gray-100 px-4 py-3 flex items-center justify-between text-[10px] text-gray-400 uppercase tracking-wider font-bold">
        <div className="flex items-center gap-4">
          <span>↑↓ Navegar</span>
          <span>↵ Abrir</span>
          <span>ESC Cerrar</span>
        </div>
        <div>{filteredBookmarks.length} Marcadores</div>
      </div>
    </div>
  );
};

export default App;

