export interface CapturedValue {
  id: string;
  value: string;
  timestamp: number;
}

export interface StorageSchema {
  capturedValues: CapturedValue[];
}

import { CapturedValue, StorageSchema } from '../types';

declare const chrome: any;

export const getValues = async (): Promise<CapturedValue[]> => {
  if (typeof chrome !== 'undefined' && chrome.storage) {
    return new Promise((resolve) => {
      chrome.storage.local.get(['capturedValues'], (result: any) => {
        resolve(result.capturedValues || []);
      });
    });
  }
  const mock = localStorage.getItem('js_mock');
  return mock ? JSON.parse(mock) : [];
};

export const saveUniqueValue = async (val: string): Promise<boolean> => {
  const text = val.trim();
  if (text.length < 2) return false;

  const current = await getValues();
  const exists = current.some(v => v.value.toLowerCase() === text.toLowerCase());

  if (exists) return false;

  const newValue: CapturedValue = {
    id: crypto.randomUUID(),
    value: text,
    timestamp: Date.now()
  };

  const updated = [newValue, ...current];

  if (typeof chrome !== 'undefined' && chrome.storage) {
    await chrome.storage.local.set({ capturedValues: updated });
  } else {
    localStorage.setItem('js_mock', JSON.stringify(updated));
  }
  return true;
};

export const removeValue = async (id: string) => {
  const current = await getValues();
  const updated = current.filter(v => v.id !== id);
  if (typeof chrome !== 'undefined' && chrome.storage) {
    await chrome.storage.local.set({ capturedValues: updated });
  } else {
    localStorage.setItem('js_mock', JSON.stringify(updated));
  }
};

export const clearAll = async () => {
  if (typeof chrome !== 'undefined' && chrome.storage) {
    await chrome.storage.local.set({ capturedValues: [] });
  } else {
    localStorage.removeItem('js_mock');
  }
};

