// JetStorage Content Script
let activeInput = null;
let savedValues = [];
let dropdownEl = null;
let indicatorEl = null;

const SENSITIVE_KEYWORDS = ['pass', 'cvv', 'card', 'secret', 'token', 'key', 'auth', 'pin'];

function isSecretField(el) {
    if (el.type === 'password') return true;
    const metadata = (el.name + el.id + el.placeholder + el.className).toLowerCase();
    return SENSITIVE_KEYWORDS.some(k => metadata.includes(k));
}

function createUIElements() {
    if (!indicatorEl) {
        indicatorEl = document.createElement('div');
        indicatorEl.id = 'js-rec-indicator';
        indicatorEl.innerHTML = `<div class="js-dot"></div><span class="js-txt">REC</span>`;
        indicatorEl.onclick = () => chrome.runtime.sendMessage({ action: "open_popup" });
        document.body.appendChild(indicatorEl);
    }
    if (!dropdownEl) {
        dropdownEl = document.createElement('div');
        dropdownEl.id = 'js-autocomplete-box';
        document.body.appendChild(dropdownEl);
    }
}

function updatePositions(el) {
    const rect = el.getBoundingClientRect();
    const scrollX = window.scrollX;
    const scrollY = window.scrollY;

    if (indicatorEl) {
        indicatorEl.style.top = `${rect.top + scrollY - 30}px`;
        indicatorEl.style.left = `${rect.right + scrollX - 50}px`;
    }

    if (dropdownEl) {
        dropdownEl.style.top = `${rect.bottom + scrollY + 4}px`;
        dropdownEl.style.left = `${rect.left + scrollX}px`;
        dropdownEl.style.width = `${rect.width}px`;
    }
}

async function syncValues() {
    return new Promise((resolve) => {
        chrome.storage.local.get(['capturedValues'], (res) => {
            savedValues = res.capturedValues || [];
            resolve(savedValues);
        });
    });
}

async function trySaveValue(val) {
    const clean = val.trim();
    if (clean.length < 2) return;

    await syncValues();
    const exists = savedValues.some(v => v.value.toLowerCase() === clean.toLowerCase());

    if (!exists) {
        const newValue = { id: Date.now().toString(), value: clean, timestamp: Date.now() };
        savedValues.unshift(newValue);
        chrome.storage.local.set({ capturedValues: savedValues });

        // Animación de éxito
        indicatorEl.classList.add('js-active-save');
        setTimeout(() => indicatorEl.classList.remove('js-active-save'), 1000);
    }
}

function renderDropdown(filter = '') {
    if (!dropdownEl) return;
    const matches = savedValues
        .filter(v => v.value.toLowerCase().includes(filter.toLowerCase()))
        .slice(0, 5);

    if (matches.length === 0) {
        dropdownEl.style.display = 'none';
        return;
    }

    dropdownEl.innerHTML = matches.map(m => `
        <div class="js-suggest-item" data-val="${m.value}">
            <span class="js-suggest-txt">${m.value}</span>
            <span class="js-suggest-tag">JetStorage</span>
        </div>
    `).join('');

    dropdownEl.style.display = 'block';

    dropdownEl.querySelectorAll('.js-suggest-item').forEach(item => {
        item.onmousedown = (e) => {
            e.preventDefault();
            if (activeInput) {
                activeInput.value = item.dataset.val;
                activeInput.dispatchEvent(new Event('input', { bubbles: true }));
                dropdownEl.style.display = 'none';
            }
        };
    });
}

// Global Listeners
document.addEventListener('focusin', async (e) => {
    const el = e.target;
    if ((el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') && !isSecretField(el)) {
        activeInput = el;
        createUIElements();
        indicatorEl.style.display = 'flex';
        updatePositions(el);
        await syncValues();
        renderDropdown(el.value);
    }
});

document.addEventListener('focusout', () => {
    setTimeout(() => {
        if (indicatorEl) indicatorEl.style.display = 'none';
        if (dropdownEl) dropdownEl.style.display = 'none';
    }, 200);
});

document.addEventListener('input', (e) => {
    if (e.target === activeInput) {
        updatePositions(activeInput);
        renderDropdown(activeInput.value);

        // Debounce simple para el guardado
        clearTimeout(activeInput._jsTimer);
        activeInput._jsTimer = setTimeout(() => trySaveValue(activeInput.value), 1200);
    }
});

window.addEventListener('resize', () => activeInput && updatePositions(activeInput));
window.addEventListener('scroll', () => activeInput && updatePositions(activeInput), true);

